import{_ as t,c as o,o as a,a1 as n}from"./chunks/framework.DDNAyvCW.js";const i="/assets/autocomplete.C49UdfEG.png",g=JSON.parse('{"title":"Command Autocomplete","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/autocomplete/index.md","filePath":"docs/terminal/autocomplete/index.md"}'),s={name:"docs/terminal/autocomplete/index.md"};function r(l,e,m,c,u,d){return a(),o("div",null,e[0]||(e[0]=[n('<h1 id="command-autocomplete" tabindex="-1">Command Autocomplete <a class="header-anchor" href="#command-autocomplete" aria-label="Permalink to &quot;Command Autocomplete&quot;">​</a></h1><p>Chaterm provides a command autocomplete feature that automatically suggests commands as you type in the terminal, helping you input common commands faster.</p><p><img src="'+i+'" alt=""></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Command autocomplete combines the following sources:</p><ul><li><strong>Command History</strong>: Supports cross-host command recommendations, prioritizing history from the current server while supplementing with frequently used commands from other servers.</li><li><strong>Built-in Command Library</strong>: Supplements with common Linux/Shell commands.</li><li><strong>AI Smart Suggestions (Optional)</strong>: Generates more complete command suggestions based on your current input.</li></ul><p>Cross-host recommendations prioritize matching the current server&#39;s usage patterns first, then supplement with related commands you frequently use on other servers.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><ol><li>Start typing a command in the terminal, and the autocomplete panel will appear automatically.</li><li>Press <code>→</code> to enter selection mode.</li><li>Press <code>↑</code> / <code>↓</code> to switch between suggestions.</li><li>Press <code>Enter</code> to confirm and insert the command.</li><li>Press <code>Esc</code> or <code>←</code> to exit selection / close the panel.</li></ol><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>You can enable or disable <strong>Autocomplete</strong> in <strong>Settings &gt; Extension Settings</strong>:</p><ul><li><strong>Enabled</strong>: Show autocomplete suggestions while typing (recommended).</li><li><strong>Disabled</strong>: Hide the autocomplete panel and type commands manually.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="the-autocomplete-panel-is-not-showing-up" tabindex="-1">The autocomplete panel is not showing up? <a class="header-anchor" href="#the-autocomplete-panel-is-not-showing-up" aria-label="Permalink to &quot;The autocomplete panel is not showing up?&quot;">​</a></h3><ul><li>Make sure <strong>Autocomplete</strong> is enabled in <strong>Settings &gt; Extension Settings</strong>.</li><li>Type a command prefix first and wait for the suggestions to refresh.</li></ul><h3 id="ai-suggestions-are-not-appearing" tabindex="-1">AI suggestions are not appearing? <a class="header-anchor" href="#ai-suggestions-are-not-appearing" aria-label="Permalink to &quot;AI suggestions are not appearing?&quot;">​</a></h3><ul><li>AI suggestions may be temporarily unavailable during network issues, but local autocomplete is not affected.</li></ul>',17)]))}const h=t(s,[["render",r]]);export{g as __pageData,h as default};
